import UIKit
import RealmSwift
import Alamofire

// MARK: - Constants

let BASE_URL = "https://api.example.com"
let REALM_DB_NAME = "Stocks"

// MARK: - Models

class Stock: Object {
    @objc dynamic var symbol: String = ""
    @objc dynamic var name: String = ""
    @objc dynamic var price: Double = 0.0
    @objc dynamic var quantity: Int = 0
    
    override class func primaryKey() -> String? {
        return "symbol"
    }
}

class Portfolio: Object {
    @objc dynamic var id: String = UUID().uuidString
    let stocks = List<Stock>()
    
    override class func primaryKey() -> String? {
        return "id"
    }
}

// MARK: - API Manager

class APIManager {
    static let shared = APIManager()
    
    private init() {}
    
    func fetchStocks(completion: @escaping ([String]) -> Void) {
        Alamofire.request(BASE_URL + "/stocks").responseJSON { response in
            switch response.result {
            case .success(let value):
                var stockSymbols: [String] = []
                if let data = value as? [[String: Any]] {
                    for stock in data {
                        stockSymbols.append(stock["symbol"] as! String)
                    }
                }
                completion(stockSymbols)
            case .failure(let error):
                print(error.localizedDescription)
            }
        }
    }
    
    func executeTrade(symbol: String, quantity: Int, completion: @escaping (Bool) -> Void) {
        Alamofire.request(BASE_URL + "/trade", method: .post, parameters: ["symbol": symbol, "quantity": quantity]).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let data = value as? [String: Any] {
                    guard let success = data["success"] as? Bool else { return }
                    completion(success)
                } else {
                    print("Invalid response")
                }
            case .failure(let error):
                print(error.localizedDescription)
            }
        }
    }
}

// MARK: - Trading View Controller

class TradingViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    
    private let tableView = UITableView()
    private var stocks: [String] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        APIManager.shared.fetchStocks { [weak self] stockSymbols in
            self?.stocks = stockSymbols
            self?.tableView.reloadData()
        }
        
        tableView.dataSource = self
        tableView.delegate = self
        
        view.addSubview(tableView)
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return stocks.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = UITableViewCell()
        
        // Configure cell
        cell.textLabel?.text = stocks[indexPath.row]
        
        return cell
    }
    
    @IBAction func tradeButtonTapped(_ sender: UIButton) {
        guard let selectedIndexPath = tableView.indexPathForSelectedRow else { return }
        let selectedSymbol = stocks[selectedIndexPath.row]
        
        let quantity = Int.random(in: 1...100)
        APIManager.shared.executeTrade(symbol: selectedSymbol, quantity: quantity) { [weak self] success in
            if success {
                print("Trade executed successfully")
            } else {
                print("Error executing trade")
            }
        }
    }
}